[{"location":"spectralmodelingapi/#Spectral-Modeling-API","page":"Spectral Modeling API","title":"Spectral Modeling API","text":"","category":"section"},{"location":"spectralmodelingapi/","page":"Spectral Modeling API","title":"Spectral Modeling API","text":"Spectral Modeling API","category":"page"},{"location":"spectrographs/#Spectrographs","page":"Spectrographs","title":"Spectrographs","text":"","category":"section"},{"location":"reductiontutorial/#Reduction-Tutorials","page":"Reduction Tutorials","title":"Reduction Tutorials","text":"","category":"section"},{"location":"reductiontutorial/#Example-1-with-iSHELL","page":"Reduction Tutorials","title":"Example 1 with iSHELL","text":"","category":"section"},{"location":"reductiontutorial/","page":"Reduction Tutorials","title":"Reduction Tutorials","text":"In this example, we reduce spectra of Vega recorded with the iSHELL spectrograph in KGAS mode. Flat-field correction is performed.","category":"page"},{"location":"reductiontutorial/","page":"Reduction Tutorials","title":"Reduction Tutorials","text":"\n# Imports\nusing EchelleReduce\nusing Echelle.ishell\nusing Polynomials\n\n# Data path\ndata_input_path = \"Vega_Test/\"\n\n# Output directory.\noutput_path = \"reduction_results/\"\n\n# Extract all orders in KGAS mode\nextract_orders = [212:230;]\n\n# Region on the detector for iSHELL\nsregion = SpecRegion2d(\n    pixmin=200, pixmax=2048-200, # Left and right bounding pixels (spectral direction)\n    orderbottom=212, ordertop=240, # Bottom and top order for this region on the detector (not necessary that orderbottom < ordertop).\n    poly_bottom=Polynomial([-116.36685525376339, 0.20359022197025314, -5.9597390213793886e-05]), # The bottom bounding polynomial\n    poly_top=Polynomial([1858.343750000002, 0.1634374999999993, -5.078125000000014e-05]) # The top bounding polynomial\n)\n\n# Standard Optimal extraction alg, for more information, see docs on extraction.\nextractor = EmpiricalOptimalExtractor(;\n    max_iterations=20,\n    remove_background=true,\n    background_smooth_width=21,\n    oversample_profile=8,\n    trace_pos_poly_deg=4,\n    badpix_σ=5,\n    extract_aperture=:auto\n)\n\n# Create the iSHELL specific recipe object, for more information, see iSHELL docs.\nrecipe = iSHELLReduceRecipe(\n    data_input_path=data_input_path, output_path=output_path,\n    sregion=sregion,\n    base_flat_field_file=nothing,\n    slit_height=28, order_spacing=30,\n    do_flat=true, do_dark=false,\n    extractor=extractor, extract_orders=extract_orders\n)\n\n# Reduce according to the recipe.\nEchelleReduce.reduce(recipe)\n","category":"page"},{"location":"reductiontutorial/","page":"Reduction Tutorials","title":"Reduction Tutorials","text":"The majority of the behavior of each recipe is unique for each spectrograph - tailored for their unique data products. For iSHELL, three output directories are created:","category":"page"},{"location":"reductiontutorial/","page":"Reduction Tutorials","title":"Reduction Tutorials","text":"spectra - Contains the reduced spectra. See iSHELL docs on how these .fits files are formatted. calib - Contains master calibration frames. trace - Contains trace parameters derived from the master flat-fields.","category":"page"},{"location":"modspecbehavior/#Modifying-Existing-Spectrograph-Behavior","page":"Modifying Existing Spectrograph Behavior","title":"Modifying Existing Spectrograph Behavior","text":"","category":"section"},{"location":"modspecbehavior/","page":"Modifying Existing Spectrograph Behavior","title":"Modifying Existing Spectrograph Behavior","text":"How to modify spectrograph behavior","category":"page"},{"location":"reductionapi/#Reduction-API","page":"Reduction API","title":"Reduction API","text":"","category":"section"},{"location":"spectraldataapi/#Spectral-Data-API","page":"Spectral Data API","title":"Spectral Data API","text":"","category":"section"},{"location":"spectraldataapi/","page":"Spectral Data API","title":"Spectral Data API","text":"SpecData","category":"page"},{"location":"spectraldataapi/","page":"Spectral Data API","title":"Spectral Data API","text":"SpecData1d","category":"page"},{"location":"spectraldataapi/","page":"Spectral Data API","title":"Spectral Data API","text":"SpecData2d","category":"page"},{"location":"spectraldataapi/","page":"Spectral Data API","title":"Spectral Data API","text":"Echellogram","category":"page"},{"location":"spectraldataapi/","page":"Spectral Data API","title":"Spectral Data API","text":"read_spec1d","category":"page"},{"location":"spectraldataapi/","page":"Spectral Data API","title":"Spectral Data API","text":"read_spec1d","category":"page"},{"location":"spectraldataapi/","page":"Spectral Data API","title":"Spectral Data API","text":"read_image","category":"page"},{"location":"spectraldataapi/","page":"Spectral Data API","title":"Spectral Data API","text":"read_header","category":"page"},{"location":"#Echelle.jl","page":"Echelle.jl","title":"Echelle.jl","text":"","category":"section"},{"location":"","page":"Echelle.jl","title":"Echelle.jl","text":"Welcome to the documentation for Echelle.jl!","category":"page"},{"location":"","page":"Echelle.jl","title":"Echelle.jl","text":"Echelle.jl provides an interface to process and analyze Echelle spectra in the Julia programming language.","category":"page"},{"location":"#Installation","page":"Echelle.jl","title":"Installation","text":"","category":"section"},{"location":"","page":"Echelle.jl","title":"Echelle.jl","text":"begin\n    using Pkg\n    Pkg.add(url=\"https://github.com/astrobc1/CurveFitParameters.jl\")\n    Pkg.add(url=\"https://github.com/astrobc1/IterativeNelderMead.jl\")\n    Pkg.add(url=\"https://github.com/astrobc1/EchelleBase.jl\")\n    Pkg.add(url=\"https://github.com/astrobc1/EchelleReduce.jl\")\n    Pkg.add(url=\"https://github.com/astrobc1/EchelleSpectralModeling.jl\")\n    Pkg.add(url=\"https://github.com/astrobc1/Echelle.jl\")\nend","category":"page"},{"location":"spectralmodelingtutorial/#Spectral-Modeling-Tutorials","page":"Spectral Modeling Tutorials","title":"Spectral Modeling Tutorials","text":"","category":"section"},{"location":"spectralmodelingtutorial/","page":"Spectral Modeling Tutorials","title":"Spectral Modeling Tutorials","text":"Spectral Modeling tutorials","category":"page"}]
